const Reputation = lazy(() => import('./pages/Reputation'));
const BotTracking = lazy(() => import('./pages/BotTracking'));
const Messages = lazy(() => import('./pages/Messages'));
const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
const MissionOrders = lazy(() => import('./pages/MissionOrders'));
const BlogOptimizer = lazy(() => import('./pages/BlogOptimizer'));
import {
  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield, X,
  Search, Activity, BookOpen, UserCircle, AlertTriangle, AlertCircle, Info, CheckCircle
} from 'lucide-react';
import { I18nProvider, useTranslation, LanguageSelector } from './i18n';

// ── Toast Notification System ──
interface Toast {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
}

const ToastContext = createContext<{
  showToast: (type: Toast['type'], message: string) => void;
}>({ showToast: () => {} });

export const useToast = () => useContext(ToastContext);

const ToastContainer: React.FC<{ toasts: Toast[]; onRemove: (id: string) => void }> = ({ toasts, onRemove }) => {
  return (
    <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-2.5 pointer-events-none">
      {toasts.map((toast) => {
        const styles = {
          success: 'bg-emerald-500/15 border-emerald-500/30 text-emerald-300',
          error: 'bg-red-500/15 border-red-500/30 text-red-300',
          info: 'bg-blue-500/15 border-blue-500/30 text-blue-300',
        };
        const icons = { success: '✓', error: '✕', info: 'ℹ' };
        return (
          <div
            key={toast.id}
            className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl border backdrop-blur-xl shadow-2xl shadow-black/40 animate-in slide-in-from-right fade-in duration-300 ${styles[toast.type]}`}
            onClick={() => onRemove(toast.id)}
          >
            <span className="text-sm font-bold">{icons[toast.type]}</span>
            <span className="text-sm font-medium">{toast.message}</span>
          </div>
        );
      })}
    </div>
  );
};
"}

{"content":"import { useEffect, useMemo, useState, type PropsWithChildren } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { demoAssignments } from '../../lib/demo-data';
import { getSectorUiMeta } from '../../lib/constants';
import { isSupabaseConfigured, supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { getProfileSectorTargets } from '../../utils/sector-targeting';

interface NavItem {
  label: string;
  path: string;
  icon: string;
}

const NAV_ITEMS: NavItem[] = [
  { label: 'Radar', path: '/radar', icon: 'R' },
  { label: 'Relances', path: '/pipeline', icon: 'S' },
  { label: 'Ciblage', path: '/sources', icon: 'C' },
  { label: 'Config', path: '/reglages', icon: 'P' },
];

/**
 * Shell global de l'application avec sidebar desktop et tabbar mobile.
 */
export const AppLayout = ({ children }: PropsWithChildren): JSX.Element => {
  const { profile, logout } = useAuth();
  const location = useLocation();
  const [unreadCount, setUnreadCount] = useState<number>(0);
  const primaryTarget = getProfileSectorTargets(profile)[0];
  const sectorMeta = getSectorUiMeta(primaryTarget?.id, primaryTarget?.label);

  useEffect(() => {
    if (!profile?.id) {
      return;
    }
    if (!isSupabaseConfigured) {
      const count = demoAssignments.filter((item) => item.status === 'new').length;
      setUnreadCount(count);
      return;
    }
    const fetchCount = async (): Promise<void> => {
      const { count } = await supabase
        .from('prospect_assignments')
        .select('id', { head: true, count: 'exact' })
        .eq('user_id', profile.id)
        .eq('status', 'new');
      setUnreadCount(count ?? 0);
    };
    void fetchCount();
  }, [profile?.id]);

  const creditsSummary = useMemo(() => {
    if (!profile) {
      return {
        balance: 0,
        spent: 0,
        purchased: 0,
        usagePercent: 0,
      };
    }
    const spent = profile.credits_total_spent;
    const purchased = profile.credits_total_purchased;
    const usagePercent = purchased > 0 ? Math.min(100, (spent / purchased) * 100) : 0;
    return {
      balance: profile.credits_balance,
      spent,
      purchased,
      usagePercent,
    };
  }, [profile]);

  return (
    <div className="min-h-screen bg-leadradar-bg text-white">
      <aside className="fixed left-0 top-0 hidden h-screen w-[220px] border-r border-leadradar-border bg-leadradar-bg md:flex md:flex-col">
        <div className="border-b border-leadradar-border px-5 py-6">
          <div className="flex items-center gap-2">
            <span className="grid h-7 w-7 place-items-center rounded-full bg-emerald-500/20 text-xs text-emerald-300">LR</span>
            <h1 className="font-outfit text-xl font-bold">LeadRadar</h1>
          </div>
          <span
            className="mt-3 inline-flex rounded-full px-2 py-1 text-xs font-semibold"
            style={{ backgroundColor: `${sectorMeta.color}24`, color: sectorMeta.color }}
          >
            {sectorMeta.icon} {sectorMeta.label}
          </span>
        </div>

        <nav className="flex-1 px-3 py-4">
          <ul className="space-y-1.5">
            {NAV_ITEMS.map((item) => {
              const active = location.pathname === item.path;
              return (
                <li key={item.path}>
                  <Link
                    to={item.path}
                    className="group relative flex items-center justify-between rounded-lg px-3 py-2 text-sm text-slate-300 transition hover:bg-slate-900/80 hover:text-white"
                  >
                    {active ? (
                      <span
                        className="absolute left-0 top-1 h-[calc(100%-8px)] w-[3px] rounded-r""}

